const d = $input.first().json;
const ctx = d.context;
const prompt = `Ты — юридический ассистент по трудовому праву. Твоя задача — кратко и точно сформулировать нарушение трудовых обязанностей со ссылками на нормативные акты.

## Данные о нарушении
Сотрудник: ${ctx.employee?.name || '[не указано]'}
Должность: ${ctx.employee?.position || '[не указано]'}
Подразделение: ${ctx.employee?.department || '[не указано]'}
Дата нарушения: ${ctx.violation?.date || '[не указано]'}
Описание: ${ctx.violation?.description || 'Прогул — отсутствие на рабочем месте без уважительной причины'}
Уважительная причина: ${ctx.respectableReason ? 'Есть: ' + ctx.respectableReasonComment : 'Отсутствует'}

## Чеклист (внутренняя инструкция)
${d.checklist_content}

## Нормативная база
${d.tk_content}

## Задача
Сформулируй нарушение в 2-4 предложениях для включения в служебную записку. Укажи конкретные статьи, пункты. Формат: юридически грамотно, сухо, без лишних слов.
Отвечай ТОЛЬКО формулировкой нарушения, без вводных фраз.`;
return [{ json: { ...d, prompt_rag: prompt } }];

const r = $input.first().json;
const violations = r.response?.trim() || '[Не удалось сформулировать нарушение]';
const prev = $('Vision: анализ доказательств (заглушка)').first().json;
return [{ json: {
  context: prev.context,
  dates: prev.dates,
  checklist_content: prev.checklist_content,
  tk_content: prev.tk_content,
  vision_analysis: prev.vision_analysis,
  violations
} }];

// Для данного сценария акт об отсутствии не требуется
// act_text остаётся пустым — финальный вывод это учтёт
const d = $input.first().json;
return [{ json: { ...d, act_text: '' } }];

const r = $input.first().json;
// Если пришли из Ollama — берём response
// Если пришли из «Акт не нужен» — берём act_text (пустой)
const act_text = r.response?.trim() || r.act_text || '';
const prev = $('Объединить нарушения').first().json;
return [{ json: {
  context: prev.context,
  dates: prev.dates,
  vision_analysis: prev.vision_analysis,
  violations: prev.violations,
  act_text
} }];

const r = $input.first().json;
const sz_text = r.response?.trim() || '[Не удалось сгенерировать служебную записку]';
const prev = $('Объединить акт').first().json;
const actBlock = prev.act_text
  ? `📋 АКТ ОБ ОТСУТСТВИИ НА РАБОЧЕМ МЕСТЕ

${prev.act_text}

---

`
  : '';
const output = `✅ Документы сформированы!

---

${actBlock}📝 СЛУЖЕБНАЯ ЗАПИСКА

${sz_text}

---

⚠️ Проверьте документы перед отправкой. Поля [УТОЧНИТЬ] требуют вашего заполнения.
После проверки — передайте пакет Черепановой Т. или Касмыниной О.`;
return [{ json: { output, act_text: prev.act_text, sz_text } }];

