const raw = $input.first().json;
let data = raw;
if (raw.query && typeof raw.query === 'object' && !Array.isArray(raw.query)) {
  data = raw.query;
} else if (typeof raw.input === 'string') {
  try { data = JSON.parse(raw.input); } catch(e) {}
} else if (typeof raw.query === 'string') {
  try { data = JSON.parse(raw.query); } catch(e) {}
}
if (!data.employee) throw new Error('hr_generate: не переданы данные employee. Получено: ' + JSON.stringify(raw));
if (!data.violation) throw new Error('hr_generate: не переданы данные violation.');
data.scenario = data.scenario || 'progul_ochny';
return [{ json: {
  context: data,
  violationDate: data.violation.date,
  discoveryDate: data.violation.discoveryDate
} }];
